"use strict";(self.webpackChunkapp=self.webpackChunkapp||[]).push([[9635],{15903(e,t,i){i.r(t),i.d(t,{assets:()=>l,contentTitle:()=>s,default:()=>h,frontMatter:()=>r,metadata:()=>n,toc:()=>c});const n=JSON.parse('{"id":"lore/sigil","title":"Sigil","description":"Sigil homebrew content for The Wandering Realm.","source":"@site/docs/lore/sigil.md","sourceDirName":"lore","slug":"/lore/sigil","permalink":"/The-Wandering-Oracle/docs/lore/sigil","draft":false,"unlisted":false,"editUrl":"https://github.com/Sazendrak/The-Wandering-Handbook/edit/main/docs/lore/sigil.md","tags":[{"inline":true,"label":"lore","permalink":"/The-Wandering-Oracle/docs/tags/lore"}],"version":"current","frontMatter":{"title":"Sigil","sidebar_label":"Sigil","tags":["lore"],"description":"Sigil homebrew content for The Wandering Realm.","source_url":"https://the-wandering-realm.fandom.com/wiki/Sigil"},"sidebar":"loreSidebar","previous":{"title":"Lore","permalink":"/The-Wandering-Oracle/docs/lore/"},"next":{"title":"The Destruction of Docker\'s Bay","permalink":"/The-Wandering-Oracle/docs/lore/the-destruction-of-docker\'s-bay"}}');var o=i(74848),a=i(28453);const r={title:"Sigil",sidebar_label:"Sigil",tags:["lore"],description:"Sigil homebrew content for The Wandering Realm.",source_url:"https://the-wandering-realm.fandom.com/wiki/Sigil"},s="Sigil",l={},c=[];function d(e){const t={h1:"h1",header:"header",p:"p",...(0,a.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.header,{children:(0,o.jsx)(t.h1,{id:"sigil",children:"Sigil"})}),"\n",(0,o.jsx)(t.p,{children:"Sigil Clarifications"}),"\n",(0,o.jsx)(t.p,{children:"Sigil, the City of Doors, is a fairly special place in the multiverse. It is the ultimate neutral ground where people of all planes and background can meet and coexist. It also comes with some special rules, courtesy of the Lady of Pain, the godlike ruler of the mind bending city."}),"\n",(0,o.jsx)(t.p,{children:"Access to the city is granted via portals, which can be any threshold from a doorway to window or a simple clearing in a forest, and is accessed via a portal key which can be anything from a literal key to a simple thought or whistled tune as you pass the threshold. These portals are not static and can be open for centuries, seconds, or for a five uses. In other words, access is based DM/Lady of Pain discretion."}),"\n",(0,o.jsx)(t.p,{children:"Teleportation within the city does not function. Need to get around using good old fashioned leg power and it would be prudent to hire a guide if you're not a native or very familiar with the occasional loops of Mc Escher esque architecture."}),"\n",(0,o.jsx)(t.p,{children:"Creatures or people spotted in Sigil are not considered to be within their natural environment for the purposes of Shapechange, Poly, etc unless the creature is native/unique to the city or Outlands such as a Cranium Rat Squeaker or Sunfly."}),"\n",(0,o.jsx)(t.p,{children:"Binding and summoning magics also do not function within the city. Can't exactly allow the celestials to go around binding the fiends walking about, and vice versa. This is a city of neutrality, where all are permitted so long as they behave."}),"\n",(0,o.jsx)(t.p,{children:"Items or knowledge brought back from alternate universes, timelines, settings, don't transfer to our main setting."}),"\n",(0,o.jsx)(t.p,{children:"Space is... weird... in the city. Buildings move seemingly on their own, space is simultaneously compact and infinite, travel between any two places seeming to take a indeterminate amount of time. One can walk for years to get down a city block or seconds to cross to the other side of the city. It is as difficult to traverse as the DM desires and the space for new construction is seemingly infinite."}),"\n",(0,o.jsx)(t.p,{children:"Laws of the Lady"}),"\n",(0,o.jsx)(t.p,{children:"Worship of the Lady is prohibited."}),"\n",(0,o.jsx)(t.p,{children:"No harm may come to any dabus."}),"\n",(0,o.jsx)(t.p,{children:"There are to be no challenges to the Lady's ultimate rule or authority within Sigil."}),"\n",(0,o.jsx)(t.p,{children:"Any action which harms the city of Sigil either directly or indirectly will be considered as a direct attack against the Lady herself, and punished appropriately."}),"\n",(0,o.jsx)(t.p,{children:"No divine entity may enter Sigil."}),"\n",(0,o.jsx)(t.p,{children:"There may be at no time more than 15 factions operating within Sigil. (Though this rule was put into place during the Great Upheaval, it is unknown if it is still amongst her laws, and the dabus have refused comment. Most haven't risked testing it.)"}),"\n",(0,o.jsx)(t.p,{children:"However, their are more laws, but are determined and enforced by internal factions of the city and are not ultimate rules laid down by the Lady of Pain, who has instantly flayed and killed even the most powerful of adventurers for so much as looking at her. Thankfully she isn't seen around much."})]})}function h(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},28453(e,t,i){i.d(t,{R:()=>r,x:()=>s});var n=i(96540);const o={},a=n.createContext(o);function r(e){const t=n.useContext(a);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:r(e.components),n.createElement(a.Provider,{value:t},e.children)}}}]);